FILES={
  'src/app/access/page.tsx': '',
  'src/app/projects/[id]/access/page.tsx': '',
  'src/app/projects/[id]/page.tsx': '',
}
for rel,b64 in FILES.items():
    d=os.path.dirname(rel)
    if d: os.makedirs(d,exist_ok=True)
